from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

@app.route('/api/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def api_gateway(path):
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return jsonify({'error': 'Authorization header is missing'}), 401

    token = auth_header.split(" ")[1]
    try:
        # Decode the token without verification for development
        claims = jwt.decode(token, options={"verify_signature": False})
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

    # Forward the claims to the backend service
    backend_response = forward_to_backend(path, claims)
    return backend_response

def forward_to_backend(path, claims):
    # Here you would implement the logic to forward the request to the actual backend service
    # For demonstration, we will just return the claims
    return jsonify({'message': 'Forwarded to backend', 'claims': claims})

if __name__ == '__main__':
    app.run(debug=True)